106 | impl AppState {
107 |     fn input_char_count(&self) -> usize {
108 |         self.input.chars().count()
109 |     }
110 | 
111 |     fn char_to_byte_index(&self, char_index: usize) -> usize {
112 |         if char_index == 0 {
113 |             return 0;
114 |         }
115 |         self.input
116 |             .char_indices()
117 |             .nth(char_index)
118 |             .map(|(idx, _)| idx)
119 |             .unwrap_or_else(|| self.input.len())
120 |     }
121 | 
122 |     fn char_at(&self, char_index: usize) -> Option<char> {
123 |         self.input.chars().nth(char_index)
124 |     }
125 | 
126 |     pub fn clamp_input_cursor(&mut self) {
127 |         self.input_cursor = self.input_cursor.min(self.input_char_count());
128 |     }
129 | 
130 |     pub fn ensure_input_cursor_visible(&mut self, visible_width: usize) {
131 |         if visible_width == 0 {
132 |             self.input_scroll = self.input_cursor;
133 |             return;
134 |         }
135 |         if self.input_cursor < self.input_scroll {
136 |             self.input_scroll = self.input_cursor;
137 |         } else if self.input_cursor >= self.input_scroll.saturating_add(visible_width) {
138 |             self.input_scroll = self
139 |                 .input_cursor
140 |                 .saturating_sub(visible_width.saturating_sub(1));
141 |         }
142 |     }
143 | 
144 |     pub fn move_cursor_left(&mut self) {
145 |         if self.input_cursor > 0 {
146 |             self.input_cursor -= 1;
147 |         }
148 |     }
149 | 
150 |     pub fn move_cursor_right(&mut self) {
151 |         if self.input_cursor < self.input_char_count() {
152 |             self.input_cursor += 1;
153 |         }
154 |     }
155 | 
156 |     pub fn move_cursor_word_left(&mut self) {
157 |         self.clamp_input_cursor();
158 |         while self.input_cursor > 0
159 |             && self
160 |                 .char_at(self.input_cursor - 1)
161 |                 .is_some_and(char::is_whitespace)
162 |         {
163 |             self.input_cursor -= 1;
164 |         }
165 |         while self.input_cursor > 0
166 |             && self
167 |                 .char_at(self.input_cursor - 1)
168 |                 .is_some_and(|c| !c.is_whitespace())
169 |         {
170 |             self.input_cursor -= 1;
171 |         }
172 |     }
173 | 
174 |     pub fn move_cursor_word_right(&mut self) {
175 |         self.clamp_input_cursor();
176 |         while self.input_cursor < self.input_char_count()
177 |             && self.char_at(self.input_cursor).is_some_and(char::is_whitespace)
178 |         {
179 |             self.input_cursor += 1;
180 |         }
181 |         while self.input_cursor < self.input_char_count()
182 |             && self
183 |                 .char_at(self.input_cursor)
184 |                 .is_some_and(|c| !c.is_whitespace())
185 |         {
186 |             self.input_cursor += 1;
187 |         }
188 |     }
189 | 
190 |     pub fn move_cursor_home(&mut self) {
191 |         self.input_cursor = 0;
192 |     }
193 | 
194 |     pub fn move_cursor_end(&mut self) {
195 |         self.input_cursor = self.input_char_count();
196 |     }
