207 |     pub fn delete_backspace(&mut self) {
208 |         self.clamp_input_cursor();
209 |         if self.input_cursor == 0 {
210 |             return;
211 |         }
212 |         let start = self.char_to_byte_index(self.input_cursor - 1);
213 |         let end = self.char_to_byte_index(self.input_cursor);
214 |         self.input.replace_range(start..end, "");
215 |         self.input_cursor -= 1;
216 |         self.history_index = None;
217 |         self.refresh_slash_suggestions();
218 |     }
219 | 
