222 |         if self.input_cursor >= self.input_char_count() {
223 |             return;
224 |         }
225 |         let start = self.char_to_byte_index(self.input_cursor);
226 |         let end = self.char_to_byte_index(self.input_cursor + 1);
227 |         self.input.replace_range(start..end, "");
228 |         self.history_index = None;
229 |         self.refresh_slash_suggestions();
230 |     }
