 26 | pub fn ui(f: &mut Frame, app: &mut App) {
 27 |     match app.state.view_mode {
 28 |         ViewMode::Chat => render_chat_view(f, app),
 29 |         ViewMode::Sessions => render_sessions_view(f, app),
 30 |         ViewMode::Swarm => render_swarm_view(f, &mut app.state.swarm, f.area()),
 31 |         ViewMode::Ralph => render_ralph_view(f, &mut app.state.ralph, f.area()),
 32 |         ViewMode::Bus => {
 33 |             let mut registered_agents = app
 34 |                 .state
 35 |                 .worker_bridge_registered_agents
 36 |                 .iter()
 37 |                 .cloned()
 38 |                 .collect::<Vec<_>>();
 39 |             registered_agents.sort();
 40 |             let summary = ProtocolSummary {
 41 |                 cwd_display: app.state.cwd_display.clone(),
 42 |                 worker_id: app.state.worker_id.clone(),
 43 |                 worker_name: app.state.worker_name.clone(),
 44 |                 a2a_connected: app.state.a2a_connected,
 45 |                 processing: app.state.worker_bridge_processing_state,
 46 |                 registered_agents,
 47 |                 queued_tasks: app.state.worker_task_queue.len(),
 48 |                 recent_task: app.state.recent_tasks.last().cloned(),
 49 |             };
 50 |             render_bus_log_with_summary(f, &mut app.state.bus_log, f.area(), Some(summary))
 51 |         }
 52 |         ViewMode::Help => {
 53 |             let area = f.area();
 54 |             let lines = crate::tui::help::build_help_lines(&app.state);
 55 |             let total_lines = lines.len();
 56 |             let content_height = area.height.saturating_sub(2) as usize;
 57 |             let max_scroll = total_lines.saturating_sub(content_height);
 58 |             if app.state.help_scroll.offset > max_scroll {
 59 |                 app.state.help_scroll.offset = max_scroll;
 60 |             }
 61 |             let scroll_offset = app.state.help_scroll.offset;
 62 | 
 63 |             let widget = Paragraph::new(lines)
 64 |                 .block(
 65 |                     Block::default()
 66 |                         .borders(Borders::ALL)
 67 |                         .title(" Help ")
 68 |                         .border_style(Style::default().fg(Color::Yellow)),
 69 |                 )
 70 |                 .wrap(Wrap { trim: false })
 71 |                 .scroll((scroll_offset as u16, 0));
 72 |             f.render_widget(widget, area);
 73 | 
 74 |             if total_lines > content_height {
 75 |                 use ratatui::widgets::{Scrollbar, ScrollbarOrientation, ScrollbarState};
 76 |                 let mut sb_state = ScrollbarState::new(total_lines).position(scroll_offset);
 77 |                 f.render_stateful_widget(
 78 |                     Scrollbar::new(ScrollbarOrientation::VerticalRight),
 79 |                     area,
 80 |                     &mut sb_state,
 81 |                 );
 82 |             }
 83 |         }
 84 |         ViewMode::Settings => render_settings(f, f.area(), &app.state.status),
 85 |         ViewMode::Lsp => render_lsp(f, f.area(), &app.state.cwd_display, &app.state.status),
 86 |         ViewMode::Rlm => render_rlm(
 87 |             f,
 88 |             f.area(),
 89 |             &app.state.cwd_display,
 90 |             &app.state.status,
 91 |             app.state.sessions.len(),
 92 |             app.state.selected_session,
 93 |         ),
 94 |     }
