105 | fn render_chat_view(f: &mut Frame, app: &mut App) {
106 |     let area = f.area();
107 |     let suggestions_visible = app.state.slash_suggestions_visible();
108 |     let chunks = Layout::default()
109 |         .direction(Direction::Vertical)
110 |         .constraints(if suggestions_visible {
111 |             [
112 |                 Constraint::Length(3),
113 |                 Constraint::Min(8),
114 |                 Constraint::Length(3),
115 |                 Constraint::Length(5),
116 |                 Constraint::Length(3),
117 |             ]
118 |             .as_ref()
119 |         } else {
120 |             [
121 |                 Constraint::Length(3),
122 |                 Constraint::Min(8),
123 |                 Constraint::Length(3),
124 |                 Constraint::Length(3),
125 |             ]
126 |             .as_ref()
127 |         })
128 |         .split(area);
129 | 
130 |     let palette = ColorPalette::marketing();
131 |     let formatter = MessageFormatter::new(chunks[1].width.saturating_sub(4) as usize);
132 | 
133 |     let title = if app.state.processing {
134 |         "CodeTether TUI — processing"
135 |     } else {
136 |         "CodeTether TUI"
137 |     };
138 | 
139 |     let session_text = app
140 |         .state
141 |         .session_id
142 |         .as_deref()
143 |         .map(|id| format!("session {id}"))
144 |         .unwrap_or_else(|| "new session".to_string());
145 | 
146 |     let mode_text = match app.state.input_mode {
147 |         InputMode::Normal => "normal",
148 |         InputMode::Editing => "edit",
149 |         InputMode::Command => "command",
150 |     };
151 | 
152 |     let header = Paragraph::new(vec![Line::from(vec![
153 |         Span::raw("Status: ").dim(),
154 |         Span::styled(
155 |             app.state.status.clone(),
156 |             Style::default().fg(if app.state.processing {
157 |                 Color::Yellow
158 |             } else {
159 |                 Color::Green
160 |             }),
161 |         ),
162 |         Span::raw("  •  ").dim(),
163 |         Span::raw(session_text).dim(),
164 |         Span::raw("  •  ").dim(),
165 |         Span::raw(format!("mode {mode_text}")).dim(),
166 |         Span::raw("  •  ").dim(),
167 |         Span::raw("Try /protocol /sessions /bus /symbols").dim(),
168 |     ])])
169 |     .block(
170 |         Block::default()
171 |             .borders(Borders::ALL)
172 |             .border_style(Style::default().fg(palette.border))
173 |             .title(title),
174 |     );
175 |     f.render_widget(header, chunks[0]);
176 | 
177 |     let mut lines: Vec<Line<'static>> = Vec::new();
178 |     if app.state.messages.is_empty() {
179 |         lines.push(Line::from(
180 |             "No messages yet. Type a prompt and press Enter, or use /help.".dim(),
181 |         ));
182 |     } else {
183 |         for msg in &app.state.messages {
184 |             let (label, role) = match msg.message_type {
185 |                 MessageType::User => ("You", "user"),
186 |                 MessageType::Assistant => ("Assistant", "assistant"),
187 |                 MessageType::System => ("System", "system"),
188 |                 MessageType::Error => ("Error", "error"),
189 |             };
190 |             let color = palette.get_message_color(role);
