215 |     fn map_syntect_color_to_ratatui(&self, color: &syntect::highlighting::Color) -> Color {
216 |         // Simple mapping - we'll use the closest ratatui color
217 |         Color::Rgb(color.r, color.g, color.b)
218 |     }
