103 |                 MessageType::User => ("You", "user"),
104 |                 MessageType::Assistant => ("Assistant", "assistant"),
105 |                 MessageType::System => ("System", "system"),
106 |                 MessageType::Error => ("Error", "error"),
107 |             };
108 |             let color = palette.get_message_color(role);
109 |             let formatted = formatter.format_content(&msg.content, role);
110 |             let mut iter = formatted.into_iter();
111 |             if let Some(first_line) = iter.next() {
112 |                 let mut spans = vec![Span::styled(
113 |                     format!("{label}: "),
114 |                     Style::default().fg(color).bold(),
115 |                 )];
116 |                 spans.extend(first_line.spans.into_iter());
117 |                 lines.push(Line::from(spans));
118 |             }
119 |             for line in iter {
120 |                 let mut spans = vec![Span::styled("  ", Style::default().fg(color))];
121 |                 spans.extend(line.spans.into_iter());
122 |                 lines.push(Line::from(spans));
123 |             }
124 |             lines.push(Line::from(""));
125 |         }
126 |     }
127 | 
128 |     let session_label = app
129 |         .state
130 |         .session_id
131 |         .as_deref()
132 |         .map(|id| {
133 |             if id.len() > 18 {
134 |                 format!("{}…", &id[..18])
135 |             } else {
136 |                 id.to_string()
137 |             }
138 |         })
139 |         .unwrap_or_else(|| "new".to_string());
140 |     let message_title = if app.state.processing {
141 |         format!(" CodeTether Agent [session:{session_label}] • processing ")
142 |     } else {
143 |         format!(" CodeTether Agent [session:{session_label}] ")
144 |     };
145 |     let chat = Paragraph::new(lines)
146 |         .block(
147 |             Block::default()
148 |                 .borders(Borders::ALL)
149 |                 .border_style(Style::default().fg(palette.border))
150 |                 .title(message_title),
151 |         )
152 |         .wrap(Wrap { trim: false })
153 |         .scroll((clamp_scroll(app.state.chat_scroll), 0));
154 |     f.render_widget(chat, chunks[0]);
155 | 
156 |     let visible_width = chunks[1].width.saturating_sub(2) as usize;
157 |     app.state.ensure_input_cursor_visible(visible_width);
158 |     let visible_input = app
159 |         .state
160 |         .input
161 |         .chars()
162 |         .skip(app.state.input_scroll)
163 |         .take(visible_width)
164 |         .collect::<String>();
165 | 
166 |     let input_title = if app.state.processing {
167 |         " Message (Processing...) "
168 |     } else if matches!(app.state.input_mode, InputMode::Command) {
169 |         " Command (/ for commands, Tab to autocomplete) "
170 |     } else {
171 |         " Message (Enter to send, / for commands) "
172 |     };
173 |     let input_border = if app.state.processing {
174 |         Color::Yellow
175 |     } else if matches!(app.state.input_mode, InputMode::Command) {
176 |         Color::Magenta
177 |     } else {
178 |         palette.border
179 |     };
180 |     let input = Paragraph::new(visible_input)
181 |         .block(
182 |             Block::default()
183 |                 .borders(Borders::ALL)
184 |                 .border_style(Style::default().fg(input_border))
185 |                 .title(input_title),
186 |         )
187 |         .wrap(Wrap { trim: false });
188 |     f.render_widget(input, chunks[1]);
189 | 
190 |     let input_inner_x = chunks[1].x.saturating_add(1);
191 |     let input_inner_y = chunks[1].y.saturating_add(1);
192 |     let cursor_col = app.state.input_cursor.saturating_sub(app.state.input_scroll);
193 |     let cursor_offset = if visible_width == 0 {
194 |         0
