 17 | impl Default for HelpScrollState {
 18 |     fn default() -> Self {
 19 |         Self { offset: 0 }
 20 |     }
 21 | }
 22 | 
 23 | impl HelpScrollState {
 24 |     pub fn scroll_up(&mut self, n: usize) {
 25 |         self.offset = self.offset.saturating_sub(n);
 26 |     }
 27 | 
