307 |                 let active_marker = if app.state.session_id.as_deref() == Some(session.id.as_str()) {
308 |                     " ●"
309 |                 } else {
310 |                     ""
311 |                 };
312 |                 let summary = format!(
313 |                     "{}{}  •  {} msgs  •  {}",
314 |                     title,
315 |                     active_marker,
316 |                     session.message_count,
317 |                     session.updated_at.format("%Y-%m-%d %H:%M")
318 |                 );
319 |                 ListItem::new(summary)
320 |             })
321 |             .collect()
322 |     };
323 | 
324 |     let mut state = ListState::default();
325 |     if !filtered.is_empty() {
326 |         state.select(Some(app.state.selected_session.min(filtered.len() - 1)));
