280 | fn format_timestamp(timestamp: SystemTime) -> String {
281 |     let secs = timestamp
282 |         .duration_since(UNIX_EPOCH)
283 |         .map(|d| d.as_secs())
284 |         .unwrap_or_default();
285 |     let day = secs % 86_400;
286 |     let hour = day / 3_600;
287 |     let minute = (day % 3_600) / 60;
288 |     let second = day % 60;
289 |     format!("{hour:02}:{minute:02}:{second:02}")
290 | }
