 61 | fn cmd_row(cmd: &str, alias: &str, desc: &str) -> Line<'static> {
 62 |     let mut spans = vec![Span::styled(
 63 |         format!("  {cmd:<14}"),
 64 |         Style::default()
 65 |             .fg(Color::Green)
 66 |             .add_modifier(Modifier::BOLD),
 67 |     )];
 68 |     if !alias.is_empty() {
 69 |         spans.push(Span::styled(
 70 |             format!("{alias:<6} "),
 71 |             Style::default().fg(Color::DarkGray),
 72 |         ));
 73 |     } else {
 74 |         spans.push(Span::raw("       ".to_string()));
 75 |     }
 76 |     spans.push(Span::raw(desc.to_string()));
 77 |     Line::from(spans)
 78 | }
