274 | fn format_timestamp(timestamp: SystemTime) -> String {
275 |     let secs = timestamp
276 |         .duration_since(UNIX_EPOCH)
277 |         .map(|d| d.as_secs())
278 |         .unwrap_or_default();
279 |     let day = secs % 86_400;
280 |     let hour = day / 3_600;
281 |     let minute = (day % 3_600) / 60;
282 |     let second = day % 60;
283 |     format!("{hour:02}:{minute:02}:{second:02}")
284 | }
