286 | fn bus_status_label_and_color(app: &App) -> (String, Color) {
287 |     let connected = app.state.a2a_connected;
288 |     let agents = app.state.worker_bridge_registered_agents.len();
289 |     let queued = app.state.worker_task_queue.len();
290 |     let processing = app.state.worker_bridge_processing_state.unwrap_or(app.state.processing);
291 | 
292 |     if connected || agents > 0 || queued > 0 {
293 |         let state = if processing { "active" } else { "idle" };
294 |         (
295 |             format!("BUS {state} ({agents}ag/{queued}q)"),
296 |             if processing { Color::Green } else { Color::Yellow },
297 |         )
298 |     } else {
299 |         ("BUS offline".to_string(), Color::DarkGray)
300 |     }
301 | }
