311 | fn render_sessions_view(f: &mut Frame, app: &mut App) {
312 |     let area = f.area();
313 |     let chunks = Layout::default()
314 |         .direction(Direction::Vertical)
315 |         .constraints([Constraint::Length(3), Constraint::Min(8), Constraint::Length(3)])
316 |         .split(area);
317 | 
318 |     let filter_display = if app.state.session_filter.is_empty() {
319 |         String::new()
320 |     } else {
321 |         format!(" [filter: {}]", app.state.session_filter)
322 |     };
323 | 
324 |     let header = Paragraph::new(vec![Line::from(vec![
325 |         Span::raw(" Session picker ").black().on_cyan(),
326 |         Span::raw(" "),
327 |         Span::raw(app.state.status.clone()).dim(),
328 |     ])])
329 |     .block(
330 |         Block::default()
331 |             .borders(Borders::ALL)
332 |             .title(format!(" Sessions (↑↓ navigate, Enter load, Esc cancel){} ", filter_display)),
333 |     );
334 |     f.render_widget(header, chunks[0]);
335 | 
336 |     let filtered = app.state.filtered_sessions();
337 |     let items: Vec<ListItem<'static>> = if filtered.is_empty() {
338 |         if app.state.session_filter.is_empty() {
339 |             vec![ListItem::new("No workspace sessions found")]
340 |         } else {
341 |             vec![ListItem::new(format!(
342 |                 "No sessions matching '{}'",
343 |                 app.state.session_filter
344 |             ))]
345 |         }
346 |     } else {
347 |         filtered
348 |             .iter()
349 |             .map(|(_, session)| {
350 |                 let title = session
351 |                     .title
352 |                     .clone()
353 |                     .unwrap_or_else(|| "Untitled session".to_string());
354 |                 let active_marker = if app.state.session_id.as_deref() == Some(session.id.as_str()) {
355 |                     " ●"
356 |                 } else {
357 |                     ""
358 |                 };
359 |                 let summary = format!(
360 |                     "{}{}  •  {} msgs  •  {}",
361 |                     title,
362 |                     active_marker,
363 |                     session.message_count,
364 |                     session.updated_at.format("%Y-%m-%d %H:%M")
365 |                 );
366 |                 ListItem::new(summary)
367 |             })
368 |             .collect()
369 |     };
370 | 
371 |     let mut state = ListState::default();
372 |     if !filtered.is_empty() {
373 |         state.select(Some(app.state.selected_session.min(filtered.len() - 1)));
374 |     }
375 | 
376 |     let list = List::new(items)
377 |         .block(Block::default().borders(Borders::ALL).title(" Available Sessions "))
378 |         .highlight_style(Style::default().bg(Color::DarkGray).fg(Color::Cyan).bold())
379 |         .highlight_symbol("▶ ");

